function solve(nums) {
    const n = nums.length;
    if (n === 0) return 0;

    const maxNum = 1e6;
    const isPrime = new Array(maxNum + 1).fill(true);
    isPrime[0] = isPrime[1] = false;
    for (let i = 2; i <= Math.sqrt(maxNum); i++) {
        if (isPrime[i]) {
            for (let j = i * i; j <= maxNum; j += i) {
                isPrime[j] = false;
            }
        }
    }

    const spf = new Array(maxNum + 1).fill(0);
    for (let i = 2; i <= maxNum; i++) {
        if (spf[i] === 0) {
            spf[i] = i;
            for (let j = i * i; j <= maxNum; j += i) {
                if (spf[j] === 0) {
                    spf[j] = i;
                }
            }
        }
    }

    const primeToIndices = new Map();
    for (let j = 0; j < n; j++) {
        const num = nums[j];
        if (num === 1) continue;
        const factors = new Set();
        let x = num;
        while (x > 1) {
            const p = spf[x];
            factors.add(p);
            while (x % p === 0) {
                x /= p;
            }
        }
        for (const p of factors) {
            if (!primeToIndices.has(p)) {
                primeToIndices.set(p, []);
            }
            primeToIndices.get(p).push(j);
        }
    }

    const dist = new Array(n).fill(-1);
    const queue = [0];
    dist[0] = 0;

    while (queue.length > 0) {
        const i = queue.shift();
        if (i === n - 1) return dist[i];

        const adjacent = [i - 1, i + 1];
        for (const j of adjacent) {
            if (j >= 0 && j < n && dist[j] === -1) {
                dist[j] = dist[i] + 1;
                queue.push(j);
            }
        }

        const currentNum = nums[i];
        if (isPrime[currentNum]) {
            const p = currentNum;
            if (primeToIndices.has(p)) {
                const indices = primeToIndices.get(p);
                for (const j of indices) {
                    if (j !== i && dist[j] === -1) {
                        dist[j] = dist[i] + 1;
                        queue.push(j);
                    }
                }
            }
        }
    }

    return -1;
}

