                    spf[j] = i.toLong()
                }
            }
        }
    }

    val primeToIndices = mutableMapOf<Long, MutableList<Int>>()
    for (j in 0 until n) {
        val num = nums[j]
        if (num == 1L) continue
        val factors = mutableSetOf<Long>()
        var x = num
        while (x > 1L) {
            val p = spf[x.toInt()]
            factors.add(p)
            while (x % p == 0L) {
                x /= p
            }
        }
        for (p in factors) {
            primeToIndices.getOrPut(p) { mutableListOf() }.add(j)
        }
    }

    val dist = LongArray(n) { -1L }
    val queue = LinkedList<Int>()
    queue.add(0)
    dist[0] = 0

    while (queue.isNotEmpty()) {
        val i = queue.pollFirst()
        if (i == n - 1) return dist[i]

        val adjacent = listOf(i - 1, i + 1)
        for (j in adjacent) {
            if (j in 0..n - 1 && dist[j] == -1L) {
                dist[j] = dist[i] + 1
                queue.add(j)
            }
        }

        val currentNum = nums[i]
        if (isPrime[currentNum.toInt()]) {
            val p = currentNum
            if (primeToIndices.containsKey(p)) {
                val indices = primeToIndices[p]!!
                for (j in indices) {
                    if (j != i && dist[j] == -1L) {
                        dist[j] = dist[i] + 1
                        queue.add(j)
                    }
                }
            }
        }
    }

    return -1L
}
